import { Injectable, signal, computed } from '@angular/core';
import { CartItem, Product } from '../models';

@Injectable({ providedIn: 'root' })
export class CartService {
  // Backend-provided data — declared as a signal per the mockup data contract.
  // The active server-side cart (GET /api/cart) will populate this.
  items = signal<CartItem[]>([
    {
      id: 'ci-1',
      productId: 'p-1',
      name: 'Aurora Wireless Headphones',
      imageUrl: 'https://picsum.photos/seed/aurora/400/300',
      unitPriceCents: 12999,
      quantity: 1,
      stockQty: 24,
    },
    {
      id: 'ci-2',
      productId: 'p-3',
      name: 'Terra Insulated Bottle 1L',
      imageUrl: 'https://picsum.photos/seed/terra/400/300',
      unitPriceCents: 3200,
      quantity: 2,
      stockQty: 60,
    },
  ]);

  readonly count = computed(() => this.items().reduce((n, i) => n + i.quantity, 0));
  readonly subtotalCents = computed(() =>
    this.items().reduce((sum, i) => sum + i.unitPriceCents * i.quantity, 0),
  );

  addProduct(product: Product, quantity = 1): void {
    const existing = this.items().find((i) => i.productId === product.id);
    if (existing) {
      this.updateQuantity(existing.id, existing.quantity + quantity);
      return;
    }
    const item: CartItem = {
      id: 'ci-' + product.id,
      productId: product.id,
      name: product.name,
      imageUrl: product.imageUrl,
      unitPriceCents: product.priceCents,
      quantity,
      stockQty: product.stockQty,
    };
    this.items.update((list) => [...list, item]);
  }

  updateQuantity(itemId: string, quantity: number): void {
    if (quantity < 1) {
      this.removeItem(itemId);
      return;
    }
    this.items.update((list) =>
      list.map((i) => (i.id === itemId ? { ...i, quantity: Math.min(quantity, i.stockQty) } : i)),
    );
  }

  removeItem(itemId: string): void {
    this.items.update((list) => list.filter((i) => i.id !== itemId));
  }

  clear(): void {
    this.items.set([]);
  }
}
